import{_ as a,o,c as s,a4 as t}from"./chunks/framework.C3khWEve.js";const m=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/guide/faq.md","filePath":"pt-BR/guide/faq.md"}'),r={name:"pt-BR/guide/faq.md"};function i(n,e,d,c,l,u){return o(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Perguntas frequentes sobre o Specialist Agent.</p><h2 id="geral" tabindex="-1">Geral <a class="header-anchor" href="#geral" aria-label="Permalink to &quot;Geral&quot;">​</a></h2><h3 id="posso-usar-sem-um-framework-pack" tabindex="-1">Posso usar sem um framework pack? <a class="header-anchor" href="#posso-usar-sem-um-framework-pack" aria-label="Permalink to &quot;Posso usar sem um framework pack?&quot;">​</a></h3><p>Sim. Os 9 agentes framework-agnostic (<code>@starter</code>, <code>@explorer</code>, <code>@finance</code>, <code>@cloud</code>, <code>@security</code>, <code>@designer</code>, <code>@data</code>, <code>@devops</code>, <code>@tester</code>) funcionam independentemente de qualquer pack. Eles não precisam de <code>ARCHITECTURE.md</code> ou arquivos específicos de pack.</p><p>Os agentes de pack (<code>@builder</code>, <code>@reviewer</code>, <code>@doctor</code>, <code>@migrator</code>) precisam de um framework pack porque dependem do <code>ARCHITECTURE.md</code> para padrões de geração de código.</p><h3 id="funciona-com-projetos-existentes" tabindex="-1">Funciona com projetos existentes? <a class="header-anchor" href="#funciona-com-projetos-existentes" aria-label="Permalink to &quot;Funciona com projetos existentes?&quot;">​</a></h3><p>Sim. Execute <code>npx specialist-agent init</code> na raiz do projeto e escolha seu framework pack. O instalador apenas adiciona arquivos markdown - não modifica seu código-fonte, dependências ou configuração.</p><p>Use <code>@explorer</code> para avaliar um codebase existente antes de fazer mudanças:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Use @explorer to assess this project&#39;s architecture and health&quot;</span></span></code></pre></div><h3 id="como-funciona-com-monorepos" tabindex="-1">Como funciona com monorepos? <a class="header-anchor" href="#como-funciona-com-monorepos" aria-label="Permalink to &quot;Como funciona com monorepos?&quot;">​</a></h3><p>Cada workspace pode ter seu próprio <code>ARCHITECTURE.md</code> e <code>CLAUDE.md</code>. Quando você abre o Claude Code em um diretório de workspace específico, os agentes leem a configuração daquele workspace.</p><p>Para padrões compartilhados entre workspaces, mantenha um <code>ARCHITECTURE.md</code> na raiz com regras comuns, e arquivos no nível do workspace para overrides.</p><h3 id="funciona-offline" tabindex="-1">Funciona offline? <a class="header-anchor" href="#funciona-offline" aria-label="Permalink to &quot;Funciona offline?&quot;">​</a></h3><p>Não. O Specialist Agent requer conexão ativa com a API do Claude. Os agentes e skills são instruções markdown que o Claude Code lê e executa - a inteligência vem do modelo Claude, não de código local.</p><h3 id="como-atualizo-o-specialist-agent" tabindex="-1">Como atualizo o Specialist Agent? <a class="header-anchor" href="#como-atualizo-o-specialist-agent" aria-label="Permalink to &quot;Como atualizo o Specialist Agent?&quot;">​</a></h3><p>Execute o instalador novamente:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>Ele sobrescreve os arquivos de agentes e skills com as versões mais recentes. Suas customizações do <code>ARCHITECTURE.md</code> são preservadas já que ficam em arquivo separado.</p><h2 id="agentes" tabindex="-1">Agentes <a class="header-anchor" href="#agentes" aria-label="Permalink to &quot;Agentes&quot;">​</a></h2><h3 id="qual-a-diferenca-entre-agentes-full-e-lite" tabindex="-1">Qual a diferença entre agentes Full e Lite? <a class="header-anchor" href="#qual-a-diferenca-entre-agentes-full-e-lite" aria-label="Permalink to &quot;Qual a diferença entre agentes Full e Lite?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspecto</th><th>Agentes Full</th><th>Agentes Lite</th></tr></thead><tbody><tr><td>Modelo</td><td>Sonnet/Opus</td><td>Haiku</td></tr><tr><td>Custo</td><td>Maior por token</td><td>~50% mais barato</td></tr><tr><td>Qualidade</td><td>Melhor para tarefas complexas</td><td>Bom para tarefas simples</td></tr><tr><td>Velocidade</td><td>Mais lento</td><td>Mais rápido</td></tr><tr><td>Melhor para</td><td>Novos módulos, PR reviews, migrações</td><td>Prototipagem, scaffolds simples, iteração</td></tr></tbody></table><p>Use agentes Lite quando velocidade importa mais que polimento. Use agentes Full quando precisão é crítica (PR reviews, migrações, investigação de bugs).</p><h3 id="posso-criar-meus-proprios-agentes" tabindex="-1">Posso criar meus próprios agentes? <a class="header-anchor" href="#posso-criar-meus-proprios-agentes" aria-label="Permalink to &quot;Posso criar meus próprios agentes?&quot;">​</a></h3><p>Sim. Veja <a href="/pr-preview/pr-56/pt-BR/customization/creating-agents.html">Criando Agentes</a> para um guia passo a passo. Agentes customizados seguem o mesmo blueprint de 5 partes:</p><ol><li><strong>Mission</strong> - O que o agente faz</li><li><strong>Workflow</strong> - Processo passo a passo</li><li><strong>Output</strong> - Formato estruturado de resultado</li><li><strong>Rules</strong> - Restrições rígidas</li><li><strong>Handoff Protocol</strong> - Quando sugerir outros agentes</li></ol><h3 id="como-os-agentes-conhecem-as-convencoes-do-meu-projeto" tabindex="-1">Como os agentes conhecem as convenções do meu projeto? <a class="header-anchor" href="#como-os-agentes-conhecem-as-convencoes-do-meu-projeto" aria-label="Permalink to &quot;Como os agentes conhecem as convenções do meu projeto?&quot;">​</a></h3><p>Todos os agentes leem <code>docs/ARCHITECTURE.md</code> antes de agir. Este arquivo define suas convenções de nomenclatura, estrutura de diretórios, regras de camadas e padrões de código. Quando você edita, o comportamento de todo agente muda imediatamente.</p><h3 id="posso-usar-agentes-de-packs-diferentes" tabindex="-1">Posso usar agentes de packs diferentes? <a class="header-anchor" href="#posso-usar-agentes-de-packs-diferentes" aria-label="Permalink to &quot;Posso usar agentes de packs diferentes?&quot;">​</a></h3><p>Cada projeto deve usar um framework pack. Os agentes de pack (<code>@builder</code>, <code>@reviewer</code>, <code>@doctor</code>, <code>@migrator</code>) são adaptados aos padrões de um framework específico. Usar agentes React em um projeto Vue geraria código incorreto.</p><p>Os agentes framework-agnostic funcionam com qualquer pack.</p><h2 id="custos" tabindex="-1">Custos <a class="header-anchor" href="#custos" aria-label="Permalink to &quot;Custos&quot;">​</a></h2><h3 id="quanto-custa-usar" tabindex="-1">Quanto custa usar? <a class="header-anchor" href="#quanto-custa-usar" aria-label="Permalink to &quot;Quanto custa usar?&quot;">​</a></h3><p>Os custos dependem do modelo Claude e do número de tokens consumidos. Veja <a href="/pr-preview/pr-56/pt-BR/reference/tokens.html">Uso de Tokens</a> para estimativas detalhadas por operação, incluindo cenários reais.</p><p><strong>Referência rápida:</strong></p><ul><li>Scaffold de componente único: ~3-5k tokens</li><li>Módulo completo com testes: ~40-60k tokens</li><li>Migração de módulo: ~50-120k tokens</li></ul><h3 id="como-posso-reduzir-custos" tabindex="-1">Como posso reduzir custos? <a class="header-anchor" href="#como-posso-reduzir-custos" aria-label="Permalink to &quot;Como posso reduzir custos?&quot;">​</a></h3><ol><li>Use <strong>agentes Lite</strong> para iteração rápida</li><li>Use <strong>skills</strong> em vez de agentes para tarefas focadas (mais barato)</li><li>Migre <strong>incrementalmente</strong> (um componente por vez)</li><li>Execute verificações automatizadas antes de reviews completos</li></ol><p>Veja <a href="/pr-preview/pr-56/pt-BR/reference/tokens.html#dicas-para-reduzir-uso-de-tokens">Dicas para Reduzir Uso de Tokens</a> para mais estratégias.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="agentes-nao-estao-seguindo-meu-architecture-md" tabindex="-1">Agentes não estão seguindo meu ARCHITECTURE.md <a class="header-anchor" href="#agentes-nao-estao-seguindo-meu-architecture-md" aria-label="Permalink to &quot;Agentes não estão seguindo meu ARCHITECTURE.md&quot;">​</a></h3><ol><li>Verifique se o arquivo está em <code>docs/ARCHITECTURE.md</code> (não na raiz do projeto)</li><li>Verifique erros de sintaxe no markdown</li><li>Execute <code>/review-check-architecture</code> para validar</li><li>Certifique-se que suas regras são explícitas - agentes seguem o que está escrito literalmente</li></ol><h3 id="skills-retornam-command-not-found" tabindex="-1">Skills retornam &quot;command not found&quot; <a class="header-anchor" href="#skills-retornam-command-not-found" aria-label="Permalink to &quot;Skills retornam &quot;command not found&quot;&quot;">​</a></h3><p>Skills não são comandos de shell. São instruções para o Claude Code. Use dentro da interface de chat do Claude Code:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Correto - dentro do Claude Code</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/dev-create-component</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ProductCard</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Errado - em um terminal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> specialist-agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev-create-component</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ProductCard</span></span></code></pre></div><h3 id="codigo-gerado-nao-corresponde-ao-meu-stack" tabindex="-1">Código gerado não corresponde ao meu stack <a class="header-anchor" href="#codigo-gerado-nao-corresponde-ao-meu-stack" aria-label="Permalink to &quot;Código gerado não corresponde ao meu stack&quot;">​</a></h3><p>Seu <code>ARCHITECTURE.md</code> pode não refletir seu stack real. Correções comuns:</p><ol><li>Atualize a seção de API client se usa Axios em vez de fetch</li><li>Atualize a seção de state management se usa uma lib de store diferente</li><li>Atualize a estrutura de diretórios se seu projeto usa um layout não-padrão</li></ol><p>Veja <a href="/pr-preview/pr-56/pt-BR/customization/editing-patterns.html">Editando Padrões</a> para exemplos de customizações comuns.</p>`,49)])])}const h=a(r,[["render",i]]);export{m as __pageData,h as default};
